/// <summary>
/// Extension of the <c>updateReportLine</c> method.
/// </summary>
/// <remarks>
/// Used to fill additional fields in the <c>InventValueReportTmpLine</c> table
/// for the <c>ETGSPAIN</c> model.
/// </remarks>
/// <param name="_tmpReportLine">InventValueReportTmpLine record.</param>
protected void updateReportLine(InventValueReportTmpLine    _tmpReportLine)
{
    if (!_tmpReportLine.ETGSPAINInventLocationAdressCity
        || !_tmpReportLine.ETGSPAINPurchOperationName)
    {
        _tmpReportLine.ETGSPAINPreWriteInventValueReportTmpLine();
    }

    next updateReportLine(_tmpReportLine);
}

/// <summary>
/// Extension of the <c>reportLinesSortOrderContainer</c> method.
/// </summary>
/// <remarks>
/// Used to manage the sort order of report lines for the <c>ETGSPAIN</c> model.
/// </remarks>
protected container reportLinesSortOrderContainer()
{        
    container   ret             = next reportLinesSortOrderContainer();
    int         containerSize   = conLen(ret);

    containerSize++;
    conPoke(ret, containerSize, fieldNum(InventValueReportTmpLine, ETGSPAINInventLocationAdressCity));

    containerSize++;
    conPoke(ret, containerSize, fieldNum(InventValueReportTmpLine, ETGSPAINPurchOperationName));


    return ret;
}
